UPDATE words SET example_en_2 = 'He had a strong knee-jerk reflex when tested.', example_ko_2 = '검사를 받을 때 그의 슬개건 반사가 강하게 나타났어요.', example_en_3 = 'The reflex to pull your hand from heat is automatic.', example_ko_3 = '열에서 손을 떼는 반사는 자동으로 일어나요.', example_en_4 = 'A reflex action happens faster than conscious thought.', example_ko_4 = '반사 작용은 의식적 사고보다 빠르게 일어나요.', example_en_5 = 'The doctor tested his reflexes with a small rubber hammer.', example_ko_5 = '의사는 작은 고무 망치로 그의 반사를 검사했어요.' WHERE id = 'w_body_B1_15';
