UPDATE words SET example_en_2 = 'She drifted in and out of consciousness during the night.', example_ko_2 = '그녀는 밤새 의식이 들락날락했어요.', example_en_3 = 'The patient regained consciousness after the surgery.', example_ko_3 = '환자는 수술 후 의식을 되찾았어요.', example_en_4 = 'He remained in full consciousness throughout the procedure.', example_ko_4 = '그는 시술 내내 완전한 의식을 유지했어요.', example_en_5 = 'Meditation can raise awareness of your own consciousness.', example_ko_5 = '명상은 자신의 의식에 대한 인식을 높일 수 있어요.' WHERE id = 'w_body_B1_17';
UPDATE words SET example_en_2 = 'He gained weight during the winter holidays.', example_ko_2 = '그는 겨울 휴가 동안 체중이 늘었어요.', example_en_3 = 'A healthy weight range varies by height and age.', example_ko_3 = '건강한 체중 범위는 키와 나이에 따라 다양해요.', example_en_4 = 'She lifted the weight above her head at the gym.', example_ko_4 = '그녀는 헬스장에서 머리 위로 무게를 들어 올렸어요.', example_en_5 = 'The baby''s weight was checked at every medical visit.', example_ko_5 = '아기의 체중은 모든 진료 방문 때 확인됐어요.' WHERE id = 'w_body_B1_18';
UPDATE words SET example_en_2 = 'Children''s height is measured regularly at school.', example_ko_2 = '아이들의 키는 학교에서 정기적으로 측정해요.', example_en_3 = 'He stood at a height of one metre eighty.', example_ko_3 = '그는 1미터 80의 키로 서 있었어요.', example_en_4 = 'Fear of height kept her from climbing the tower.', example_ko_4 = '고소공포증이 그녀가 탑을 오르는 것을 막았어요.', example_en_5 = 'The table was adjusted to a comfortable height.', example_ko_5 = '테이블은 편안한 높이로 조정되었어요.' WHERE id = 'w_body_B1_19';
UPDATE words SET example_en_2 = 'She was not happy with the shape of her body after winter.', example_ko_2 = '그녀는 겨울이 지난 후 자신의 체형이 마음에 들지 않았어요.', example_en_3 = 'He admired the lean shape of the swimmer''s body.', example_ko_3 = '그는 수영 선수의 날씬한 체형을 부러워했어요.', example_en_4 = 'The shape of the vase was unusual and eye-catching.', example_ko_4 = '그 꽃병의 모양은 독특하고 눈길을 끌었어요.', example_en_5 = 'Staying in shape requires consistent effort.', example_ko_5 = '체형을 유지하려면 꾸준한 노력이 필요해요.' WHERE id = 'w_body_B1_20';
UPDATE words SET example_en_2 = 'She liked to stretch in the evenings to unwind.', example_ko_2 = '그녀는 긴장을 풀기 위해 저녁에 스트레칭하는 것을 좋아했어요.', example_en_3 = 'The cat stretched its whole body after waking up.', example_ko_3 = '고양이는 잠에서 깨어난 후 온몸을 기지개 켰어요.', example_en_4 = 'He stretched his arms wide and took a deep breath.', example_ko_4 = '그는 팔을 넓게 펼치고 깊게 숨을 들이쉬었어요.', example_en_5 = 'Regular stretching helps maintain range of motion.', example_ko_5 = '규칙적인 스트레칭은 움직임의 범위를 유지하는 데 도움이 돼요.' WHERE id = 'w_body_B1_21';
UPDATE words SET example_en_2 = 'She tightened the strap on her backpack before the hike.', example_ko_2 = '그녀는 하이킹 전에 백팩 끈을 조였어요.', example_en_3 = 'He tightened his grip on the handlebar going downhill.', example_ko_3 = '그는 내리막길에서 핸들바를 더 꽉 잡았어요.', example_en_4 = 'Anxiety can cause muscles in the chest to tighten.', example_ko_4 = '불안은 가슴 근육을 긴장시킬 수 있어요.', example_en_5 = 'The trainer asked her to tighten her core during the plank.', example_ko_5 = '트레이너가 플랭크 자세 중 복근을 긴장시키라고 했어요.' WHERE id = 'w_body_B1_22';
UPDATE words SET example_en_2 = 'She sat in the garden to relax after a stressful day.', example_ko_2 = '그녀는 스트레스받는 하루를 보낸 후 정원에 앉아 휴식을 취했어요.', example_en_3 = 'He found it hard to relax with so much work to do.', example_ko_3 = '그는 해야 할 일이 너무 많아서 긴장을 풀기가 어려웠어요.', example_en_4 = 'Music helps her relax before going to bed.', example_ko_4 = '음악은 그녀가 잠자리에 들기 전에 긴장을 푸는 데 도움이 돼요.', example_en_5 = 'Yoga is a great way to relax both body and mind.', example_ko_5 = '요가는 몸과 마음을 모두 이완하는 훌륭한 방법이에요.' WHERE id = 'w_body_B1_23';
UPDATE words SET example_en_2 = 'Her jaw was tense from clenching it all day.', example_ko_2 = '그녀의 턱뼈는 하루 종일 꽉 다물어서 긴장되어 있었어요.', example_en_3 = 'A tense atmosphere filled the room before the announcement.', example_ko_3 = '발표 전에 긴장된 분위기가 방 안을 가득 채웠어요.', example_en_4 = 'He felt tense and could not concentrate on his work.', example_ko_4 = '그는 긴장되어 일에 집중할 수가 없었어요.', example_en_5 = 'She rolled her neck slowly to release the tense muscles.', example_ko_5 = '그녀는 긴장된 근육을 풀기 위해 천천히 목을 돌렸어요.' WHERE id = 'w_body_B1_24';
UPDATE words SET example_en_2 = 'She woke up with a numb hand from sleeping on it.', example_ko_2 = '그녀는 손을 깔고 자서 손이 저린 채로 깼어요.', example_en_3 = 'His feet went numb while standing in the snow.', example_ko_3 = '그의 발은 눈 속에 서 있다가 저렸어요.', example_en_4 = 'A numb limb can be a sign of poor circulation.', example_ko_4 = '사지가 저린 것은 혈액 순환이 좋지 않다는 신호일 수 있어요.', example_en_5 = 'The dentist gave her an injection to make the area numb.', example_ko_5 = '치과 의사가 그 부위를 무감각하게 하기 위해 주사를 놓았어요.' WHERE id = 'w_body_B1_25';
UPDATE words SET example_en_2 = 'She had an ache in her lower back from lifting boxes.', example_ko_2 = '그녀는 상자를 들다가 허리 아래쪽에 통증이 생겼어요.', example_en_3 = 'His knee ache got worse in cold and wet weather.', example_ko_3 = '그의 무릎 통증은 춥고 습한 날씨에 더 심해졌어요.', example_en_4 = 'She took a painkiller to ease the ache in her shoulder.', example_ko_4 = '그녀는 어깨 통증을 완화하기 위해 진통제를 복용했어요.', example_en_5 = 'He ignored the ache and kept working, which made it worse.', example_ko_5 = '그는 통증을 무시하고 계속 일했는데 증세가 더 악화됐어요.' WHERE id = 'w_body_B1_26';
UPDATE words SET example_en_2 = 'His throat was sore after speaking all day.', example_ko_2 = '그의 목은 하루 종일 말한 후 아팠어요.', example_en_3 = 'She had sore feet from walking in heels all evening.', example_ko_3 = '그녀는 저녁 내내 굽 높은 신발을 신고 걸어서 발이 아팠어요.', example_en_4 = 'His shoulders were sore from carrying the heavy backpack.', example_ko_4 = '그는 무거운 배낭을 메고 다녀서 어깨가 쑤셨어요.', example_en_5 = 'A warm bath can ease sore muscles after sport.', example_ko_5 = '따뜻한 목욕은 운동 후 아픈 근육을 완화할 수 있어요.' WHERE id = 'w_body_B1_27';
UPDATE words SET example_en_2 = 'She felt relief when the test results came back normal.', example_ko_2 = '검사 결과가 정상으로 나오자 그녀는 안도감을 느꼈어요.', example_en_3 = 'A cold compress brought instant relief to his swollen knee.', example_ko_3 = '냉찜질이 그의 부은 무릎에 즉각적인 완화를 가져다줬어요.', example_en_4 = 'Talking about the problem brought her some relief.', example_ko_4 = '문제에 대해 이야기하는 것이 그녀에게 어느 정도 안도감을 줬어요.', example_en_5 = 'The doctor gave him an injection for pain relief.', example_ko_5 = '의사가 통증 완화를 위해 그에게 주사를 놓았어요.' WHERE id = 'w_body_B1_28';
UPDATE words SET example_en_2 = 'She took several days to recover from the flu.', example_ko_2 = '그녀는 독감에서 회복하는 데 며칠이 걸렸어요.', example_en_3 = 'He did light exercise while recovering from the injury.', example_ko_3 = '그는 부상에서 회복하는 동안 가벼운 운동을 했어요.', example_en_4 = 'Eating well is important to help the body recover.', example_ko_4 = '몸이 회복하는 데 도움이 되도록 잘 먹는 것이 중요해요.', example_en_5 = 'She checked in with her doctor regularly to track her recovery.', example_ko_5 = '그녀는 회복 상태를 추적하기 위해 정기적으로 의사를 찾았어요.' WHERE id = 'w_body_B1_29';
UPDATE words SET example_en_2 = 'The cut on his hand healed without leaving a scar.', example_ko_2 = '그의 손에 난 상처는 흉터 없이 나았어요.', example_en_3 = 'She gave herself time to heal after the operation.', example_ko_3 = '그녀는 수술 후 회복할 시간을 가졌어요.', example_en_4 = 'Emotional wounds can take longer to heal than physical ones.', example_ko_4 = '감정적 상처는 신체적 상처보다 낫는 데 더 오래 걸릴 수 있어요.', example_en_5 = 'Rest and proper nutrition help the body heal faster.', example_ko_5 = '휴식과 적절한 영양 섭취는 몸이 더 빨리 낫는 데 도움이 돼요.' WHERE id = 'w_body_B1_30';
UPDATE words SET example_en_2 = 'She fainted during the long ceremony in the heat.', example_ko_2 = '그녀는 더운 날 긴 행사 중에 기절했어요.', example_en_3 = 'He almost fainted when he saw the large amount of blood.', example_ko_3 = '그는 많은 양의 피를 보자 거의 기절할 뻔했어요.', example_en_4 = 'She sat down quickly when she felt like she might faint.', example_ko_4 = '그녀는 기절할 것 같은 느낌이 들어 빠르게 앉았어요.', example_en_5 = 'Drinking water helps prevent fainting in hot weather.', example_ko_5 = '물을 마시면 더운 날씨에 기절을 예방하는 데 도움이 돼요.' WHERE id = 'w_body_B1_31';
UPDATE words SET example_en_2 = 'She began to shiver as the temperature dropped outside.', example_ko_2 = '밖의 기온이 내려가자 그녀는 떨기 시작했어요.', example_en_3 = 'He shivered despite wearing a thick jacket.', example_ko_3 = '그는 두꺼운 재킷을 입었음에도 몸을 떨었어요.', example_en_4 = 'The wet clothes made her shiver uncontrollably.', example_ko_4 = '젖은 옷 때문에 그녀는 몸을 걷잡을 수 없이 떨었어요.', example_en_5 = 'A shiver ran down his spine when he heard the strange sound.', example_ko_5 = '이상한 소리를 듣자 그의 등줄기에 오싹한 느낌이 스쳐갔어요.' WHERE id = 'w_body_B1_32';
UPDATE words SET example_en_2 = 'His legs trembled as he walked up to accept the award.', example_ko_2 = '그는 시상대에 걸어 올라가면서 다리가 떨렸어요.', example_en_3 = 'She trembled with cold after standing in the rain.', example_ko_3 = '그녀는 빗속에 서 있다가 추위로 몸을 떨었어요.', example_en_4 = 'The old man''s hands trembled slightly as he poured the tea.', example_ko_4 = '노인은 차를 따르면서 손이 약간 떨렸어요.', example_en_5 = 'His voice trembled with emotion as he spoke.', example_ko_5 = '그는 말하면서 감정으로 목소리가 떨렸어요.' WHERE id = 'w_body_B1_33';
UPDATE words SET example_en_2 = 'He blushed deeply when everyone looked at him.', example_ko_2 = '모두가 그를 바라보자 그는 얼굴이 새빨개졌어요.', example_en_3 = 'She tried not to blush but could not help it.', example_ko_3 = '그녀는 얼굴이 붉어지지 않으려 했지만 어쩔 수가 없었어요.', example_en_4 = 'His cheeks blushed whenever she smiled at him.', example_ko_4 = '그녀가 그에게 미소 지을 때마다 그의 볼이 붉어졌어요.', example_en_5 = 'Children blush less easily than adults in social situations.', example_ko_5 = '아이들은 사회적 상황에서 어른보다 얼굴이 덜 붉어져요.' WHERE id = 'w_body_B1_34';
UPDATE words SET example_en_2 = 'She sneezed loudly and apologised to the people around her.', example_ko_2 = '그녀는 크게 재채기하고 주변 사람들에게 사과했어요.', example_en_3 = 'He could not stop sneezing during allergy season.', example_ko_3 = '그는 알레르기 계절에 재채기를 멈출 수 없었어요.', example_en_4 = 'Always cover your mouth when you sneeze.', example_ko_4 = '재채기를 할 때는 항상 입을 가리세요.', example_en_5 = 'A sudden sneeze can be triggered by bright light.', example_ko_5 = '갑작스러운 재채기는 밝은 빛에 의해 유발될 수 있어요.' WHERE id = 'w_body_B1_35';

