UPDATE words SET example_en_2 = 'The enzyme activity decreased at low temperatures.', example_ko_2 = '낮은 온도에서 효소 활성이 감소했어요.', example_en_3 = 'Some people lack the enzyme needed to digest lactose.', example_ko_3 = '일부 사람들은 유당을 소화하는 데 필요한 효소가 부족해요.', example_en_4 = 'Enzymes in saliva begin breaking down food immediately.', example_ko_4 = '침 속의 효소는 즉시 음식을 분해하기 시작해요.', example_en_5 = 'The lab studied how the enzyme affected cell function.', example_ko_5 = '연구소는 효소가 세포 기능에 어떻게 영향을 미치는지 연구했어요.' WHERE id = 'w_body_B2_03';
UPDATE words SET example_en_2 = 'Different tissues in the body have different functions.', example_ko_2 = '신체의 다양한 조직은 각각 다른 기능을 가지고 있어요.', example_en_3 = 'She blew her nose with a soft tissue.', example_ko_3 = '그녀는 부드러운 티슈로 코를 풀었어요.', example_en_4 = 'The biopsy showed abnormal growth in the tissue.', example_ko_4 = '생검 결과 조직에 비정상적인 성장이 나타났어요.', example_en_5 = 'Connective tissue holds different body parts together.', example_ko_5 = '결합 조직은 신체의 다양한 부위를 함께 붙들어줘요.' WHERE id = 'w_body_B2_04';
